#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct Node {
    int key, val, count;
    Node(int k, int v, int c) : key(k), val(v), count(c) {}
};

class Solution {
public:
    Solution(int capacity) : capacity(capacity) {}

    int get(int key) {
        if (key2node.find(key) == key2node.end()) return -1;
        Node* node = key2node[key];
        count2node[node->count].erase(key);
        if (count2node[node->count].empty()) {
            count2node.erase(node->count);
            if (node->count == minCount) minCount++;
        }
        node->count++;
        count2node[node->count][key] = node;
        return node->val;
    }

    void put(int key, int value) {
        if (!capacity) return;
        if (key2node.find(key) != key2node.end()) {
            key2node[key]->val = value;
            get(key);
            return;
        }
        if (key2node.size() == capacity) {
            auto it = count2node[minCount].begin();
            key2node.erase(it->first);
            count2node[minCount].erase(it);
            if (count2node[minCount].empty()) count2node.erase(minCount);
        }
        key2node[key] = new Node(key, value, 1);
        count2node[1][key] = key2node[key];
        minCount = 1;
    }

private:
    int capacity;
    unordered_map<int, Node*> key2node;
    unordered_map<int, unordered_map<int, Node*>> count2node;
    int minCount = 0;
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int capacity;
    cin >> capacity;
    int numOperations;
    cin >> numOperations;
    Solution sol(capacity);
    for (int i = 0; i < numOperations; i++) {
        string operation;
        cin >> operation;
        if (operation == "get") {
            int key;
            cin >> key;
            cout << sol.get(key) << "\n";
        } else if (operation == "put") {
            int key, value;
            cin >> key >> value;
            sol.put(key, value);
        }
    }
    return 0;
}
